import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Check if user input exceeds buffer size
        if (name.length() > 10) {
            System.out.println("Input exceeds buffer size limit. Please enter a shorter name.");
            return;
        }

        byte[] buffer = new byte[10];
        Arrays.fill(buffer, (byte) 0); // Initialize buffer with zeros
        System.arraycopy(name.getBytes(), 0, buffer, 0, name.length());

        System.out.println("Hello, " + new String(buffer).trim()); // Trim any extra spaces

        // Clear sensitive data from memory
        Arrays.fill(buffer, (byte) 0);
    }
}

### Explanation:
취약유형: Buffer Overflow
